import React, { useState, useEffect } from 'react';
import axios from 'axios';
import TopNav from './TopNav';
import './Participants.css';

const Participants = () => {
  const [participants, setParticipants] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    loadParticipants();
  }, []);

  const loadParticipants = () => {
    try {
      const stored = localStorage.getItem('workplace_meeting_participants');
      if (stored) {
        const parsed = JSON.parse(stored);
        if (Array.isArray(parsed)) {
          setParticipants(parsed);
        }
      }
    } catch (e) {
      console.error('Error loading participants:', e);
    } finally {
      setLoading(false);
    }
  };

  if (loading) {
    return (
      <div className="participants-screen">
        <TopNav />
        <div className="participants-wrapper">
          <div className="participants-content">
            <div className="loading">Loading...</div>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="participants-screen">
      <TopNav />
      <div className="participants-wrapper">
        <div className="participants-top-bar">
          <h1 className="participants-title">Participants</h1>
        </div>

        <div className="participants-content">
          {participants.length === 0 ? (
            <div className="empty-state">
              <svg width="48" height="48" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5" style={{ color: '#A1A1A6', marginBottom: '16px' }}>
                <path d="M17 21v-2a4 4 0 0 0-4-4H5a4 4 0 0 0-4 4v2"></path>
                <circle cx="9" cy="7" r="4"></circle>
                <path d="M23 21v-2a4 4 0 0 0-3-3.87"></path>
                <path d="M16 3.13a4 4 0 0 1 0 7.75"></path>
              </svg>
              <p>No saved participants</p>
            </div>
          ) : (
            <div className="participants-grid">
              {participants.map((p, idx) => (
                <div key={idx} className="participant-card">
                  <div className="participant-avatar">
                    {(p.name || p.email || '?').charAt(0).toUpperCase()}
                  </div>
                  <div className="participant-info">
                    <div className="participant-name">{p.name || 'Unnamed'}</div>
                    <div className="participant-email">{p.email || 'No email'}</div>
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default Participants;
